"use client";

import { useState } from "react";
import { ZipCodeForm } from "@/components/ZipCodeForm";
import { StateInfoCard } from "@/components/StateInfoCard";
import { PromptOutput } from "@/components/PromptOutput";
import { StateSelectorModal } from "@/components/StateSelectorModal";
import { lookupState } from "@/lib/lookupState";
import { generatePrompt } from "@/lib/generatePrompt";
import type { StateElectionData } from "@/lib/types";

type AppState =
  | { stage: "idle" }
  | { stage: "loading" }
  | { stage: "not-found"; zip: string }
  | { stage: "multi-state"; zip: string; stateCodes: string[] }
  | { stage: "result"; zip: string; stateData: StateElectionData };

async function loadStateData(code: string): Promise<StateElectionData | null> {
  try {
    const mod = await import(`@/data/states/${code}.json`);
    return mod.default as StateElectionData;
  } catch {
    return null;
  }
}

export default function Home() {
  const [appState, setAppState] = useState<AppState>({ stage: "idle" });

  async function handleZipSubmit(zip: string) {
    setAppState({ stage: "loading" });

    const stateCodes = lookupState(zip);

    if (stateCodes.length === 0) {
      setAppState({ stage: "not-found", zip });
      return;
    }

    if (stateCodes.length > 1) {
      setAppState({ stage: "multi-state", zip, stateCodes });
      return;
    }

    const stateData = await loadStateData(stateCodes[0]);
    if (!stateData) {
      setAppState({ stage: "not-found", zip });
      return;
    }

    setAppState({ stage: "result", zip, stateData });
  }

  async function handleStateSelect(code: string) {
    if (appState.stage !== "multi-state") return;
    const { zip } = appState;

    setAppState({ stage: "loading" });
    const stateData = await loadStateData(code);
    if (!stateData) {
      setAppState({ stage: "not-found", zip });
      return;
    }

    setAppState({ stage: "result", zip, stateData });
  }

  const promptText =
    appState.stage === "result"
      ? generatePrompt(appState.stateData, appState.zip)
      : null;

  return (
    <div className="min-h-screen bg-gray-50">
      {/* Hero Section */}
      <header className="bg-white border-b border-gray-200">
        <div className="max-w-3xl mx-auto px-4 py-8 sm:px-6">
          <h1 className="text-3xl sm:text-4xl font-bold text-gray-900 mb-3">
            Research your ballot in minutes
          </h1>
          <p className="text-lg text-gray-600 mb-4">
            Enter your zip code to get your state&apos;s election info and a
            customized AI research prompt. Copy it, paste it into any free AI
            chatbot, and let it walk you through every race and issue.
          </p>
          <div className="flex flex-wrap gap-3 text-sm text-gray-500">
            <span>Works with:</span>
            <a
              href="https://claude.ai"
              target="_blank"
              rel="noopener noreferrer"
              className="text-blue-600 underline hover:text-blue-800"
            >
              Claude
            </a>
            <a
              href="https://chatgpt.com"
              target="_blank"
              rel="noopener noreferrer"
              className="text-blue-600 underline hover:text-blue-800"
            >
              ChatGPT
            </a>
            <a
              href="https://gemini.google.com"
              target="_blank"
              rel="noopener noreferrer"
              className="text-blue-600 underline hover:text-blue-800"
            >
              Gemini
            </a>
            <a
              href="https://grok.com"
              target="_blank"
              rel="noopener noreferrer"
              className="text-blue-600 underline hover:text-blue-800"
            >
              Grok
            </a>
          </div>
        </div>
      </header>

      <main id="main-content" className="max-w-3xl mx-auto px-4 py-8 sm:px-6">
        {/* Zip Code Entry */}
        <section className="mb-8">
          <ZipCodeForm
            onSubmit={handleZipSubmit}
            isLoading={appState.stage === "loading"}
          />
        </section>

        {/* Loading State */}
        {appState.stage === "loading" && (
          <div
            className="flex items-center gap-2 text-gray-500"
            aria-live="polite"
            role="status"
          >
            <svg
              className="w-5 h-5 animate-spin"
              fill="none"
              viewBox="0 0 24 24"
              aria-hidden="true"
            >
              <circle
                className="opacity-25"
                cx="12"
                cy="12"
                r="10"
                stroke="currentColor"
                strokeWidth="4"
              />
              <path
                className="opacity-75"
                fill="currentColor"
                d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4z"
              />
            </svg>
            <span>Looking up your state&apos;s election information...</span>
          </div>
        )}

        {/* Not Found */}
        {appState.stage === "not-found" && (
          <div
            data-testid="not-found-message"
            className="bg-amber-50 border border-amber-200 rounded-xl p-6"
            role="alert"
          >
            <h2 className="text-lg font-semibold text-amber-900 mb-2">
              Zip code not found
            </h2>
            <p className="text-amber-800 text-sm">
              We don&apos;t have data for zip code{" "}
              <strong>{appState.zip}</strong> yet. We&apos;re working on adding
              all U.S. zip codes. In the meantime, visit your{" "}
              <a
                href="https://www.usa.gov/state-election-office"
                target="_blank"
                rel="noopener noreferrer"
                className="underline"
              >
                state election office
              </a>{" "}
              for election information.
            </p>
          </div>
        )}

        {/* Multi-state selector */}
        {appState.stage === "multi-state" && (
          <StateSelectorModal
            stateCodes={appState.stateCodes}
            onSelect={handleStateSelect}
          />
        )}

        {/* Results */}
        {appState.stage === "result" && promptText && (
          <div className="space-y-6">
            <StateInfoCard stateData={appState.stateData} />
            <PromptOutput promptText={promptText} />
          </div>
        )}

        {/* Tips Section */}
        <section className="mt-12 bg-blue-50 border border-blue-200 rounded-xl p-6">
          <h2 className="text-lg font-semibold text-blue-900 mb-3">
            Tips for using the prompt
          </h2>
          <ul className="space-y-2 text-sm text-blue-800">
            <li>
              <strong>You can say &ldquo;I don&apos;t know&rdquo;</strong> — the
              AI will explain more and help you figure it out
            </li>
            <li>
              <strong>Ask it to research</strong> something for you (&ldquo;Can
              you look up this candidate&apos;s voting record?&rdquo;)
            </li>
            <li>
              <strong>Ask questions anytime</strong> — &ldquo;What does this
              position actually do?&rdquo; or &ldquo;Why does this
              matter?&rdquo;
            </li>
            <li>
              <strong>Important:</strong> AI can make mistakes. This is a
              research starting point — always verify with official sources.
            </li>
          </ul>
        </section>

        {/* Footer */}
        <footer className="mt-12 pt-6 border-t border-gray-200 text-center text-sm text-gray-500">
          <p className="mb-2">
            <strong>Share this tool</strong> with friends, family, and your
            community. The more people vote based on evidence, the better our
            elections get.
          </p>
          <p>
            Created by a human using AI tools, because everyone deserves to know
            what they&apos;re actually voting for.
          </p>
        </footer>
      </main>
    </div>
  );
}

"use client";

import type { DeadlineResult } from "@/lib/types";

interface DeadlineStatusProps {
  label: string;
  deadline: string | null;
  result: DeadlineResult;
}

const STATUS_STYLES: Record<string, string> = {
  passed: "text-gray-500 bg-gray-100",
  urgent: "text-red-700 bg-red-100",
  warning: "text-yellow-700 bg-yellow-100",
  ok: "text-green-700 bg-green-100",
  na: "text-gray-500 bg-gray-100",
};

export function DeadlineStatus({
  label,
  deadline,
  result,
}: DeadlineStatusProps) {
  const style = STATUS_STYLES[result.status] ?? STATUS_STYLES.na;

  return (
    <div className="flex items-center justify-between gap-2 py-1">
      <span className="text-sm text-gray-700 min-w-0 flex-1">{label}</span>
      {deadline && <span className="text-xs text-gray-500">{deadline}</span>}
      <span
        className={`text-xs font-medium px-2 py-0.5 rounded-full shrink-0 ${style}`}
        aria-label={`${label}: ${result.label}`}
      >
        {result.label}
      </span>
    </div>
  );
}

"use client";

import { useState } from "react";

interface PromptOutputProps {
  promptText: string;
}

export function PromptOutput({ promptText }: PromptOutputProps) {
  const [copied, setCopied] = useState(false);
  const [fallback, setFallback] = useState(false);

  async function handleCopy() {
    try {
      if (navigator.clipboard && navigator.clipboard.writeText) {
        await navigator.clipboard.writeText(promptText);
        setCopied(true);
        setFallback(false);
        setTimeout(() => setCopied(false), 2000);
      } else {
        // Fallback for older browsers
        setFallback(true);
      }
    } catch {
      setFallback(true);
    }
  }

  return (
    <div className="bg-white border border-gray-200 rounded-xl shadow-sm overflow-hidden">
      <div className="p-6 border-b border-gray-100">
        <h2 className="text-xl font-semibold text-gray-900 mb-1">
          Your Customized AI Prompt
        </h2>
        <p className="text-sm text-gray-600">
          Copy this prompt and paste it as your first message in any AI chatbot
          (Claude, ChatGPT, Gemini, Grok).
        </p>
      </div>

      {fallback && (
        <div
          className="px-6 py-3 bg-amber-50 border-b border-amber-200 text-sm text-amber-800"
          role="alert"
        >
          Clipboard not available. Select all text below and press{" "}
          <kbd className="px-1 bg-amber-100 rounded">Ctrl+C</kbd> /{" "}
          <kbd className="px-1 bg-amber-100 rounded">Cmd+C</kbd> to copy.
        </div>
      )}

      <div className="relative">
        <div
          data-testid="prompt-output"
          className="p-6 font-mono text-sm text-gray-800 bg-gray-50 max-h-[400px] overflow-y-auto whitespace-pre-wrap leading-relaxed"
          aria-label="Customized ballot research prompt"
          role="region"
        >
          {promptText}
        </div>

        <div className="p-4 border-t border-gray-200 bg-white flex items-center gap-3">
          <button
            data-testid="copy-button"
            onClick={handleCopy}
            className="px-6 py-3 bg-blue-600 text-white font-medium rounded-lg hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 min-h-[44px] flex items-center gap-2"
            aria-label="Copy prompt to clipboard"
          >
            {copied ? (
              <>
                <svg
                  className="w-4 h-4"
                  fill="none"
                  viewBox="0 0 24 24"
                  stroke="currentColor"
                  aria-hidden="true"
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth={2}
                    d="M5 13l4 4L19 7"
                  />
                </svg>
                Copied!
              </>
            ) : (
              <>
                <svg
                  className="w-4 h-4"
                  fill="none"
                  viewBox="0 0 24 24"
                  stroke="currentColor"
                  aria-hidden="true"
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth={2}
                    d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z"
                  />
                </svg>
                Copy to Clipboard
              </>
            )}
          </button>

          {copied && (
            <span
              data-testid="copy-confirmation"
              className="text-sm text-green-600 font-medium"
              role="status"
              aria-live="polite"
            >
              Copied to clipboard!
            </span>
          )}
        </div>
      </div>
    </div>
  );
}

"use client";

import type { StateElectionData } from "@/lib/types";
import {
  getDeadlineStatus,
  formatDate,
  findNextElection,
} from "@/lib/deadlineStatus";
import { DeadlineStatus } from "./DeadlineStatus";

interface StateInfoCardProps {
  stateData: StateElectionData;
}

export function StateInfoCard({ stateData }: StateInfoCardProps) {
  const today = new Date();
  const nextElection = findNextElection(stateData.elections, today);

  const onlineStatus = getDeadlineStatus(
    stateData.registration.online.available
      ? stateData.registration.online.deadline
      : null,
    today,
  );
  const byMailStatus = getDeadlineStatus(
    stateData.registration.byMail.deadline,
    today,
  );
  const inPersonStatus = getDeadlineStatus(
    stateData.registration.inPerson.deadline,
    today,
  );

  const allDeadlinesPassed =
    stateData.registration.online.deadline &&
    stateData.registration.byMail.deadline &&
    stateData.registration.inPerson.deadline &&
    onlineStatus.status === "passed" &&
    byMailStatus.status === "passed" &&
    inPersonStatus.status === "passed";

  return (
    <div
      data-testid="state-info"
      className="bg-white border border-gray-200 rounded-xl p-6 shadow-sm"
    >
      <h2 className="text-xl font-semibold text-gray-900 mb-4">
        {stateData.stateName} Election Information
      </h2>

      {!nextElection ? (
        <p
          data-testid="no-election-message"
          className="text-gray-600"
          role="alert"
        >
          No upcoming elections found for {stateData.stateName}. Check{" "}
          <a
            href={stateData.resources.stateElectionWebsite}
            target="_blank"
            rel="noopener noreferrer"
            className="text-blue-600 underline hover:text-blue-800"
          >
            the {stateData.stateName} election website
          </a>{" "}
          for updates.
        </p>
      ) : (
        <>
          {/* Election Details */}
          <div className="mb-4 pb-4 border-b border-gray-100">
            <h3 className="text-sm font-medium text-gray-500 uppercase tracking-wide mb-2">
              Next Election
            </h3>
            <p
              data-testid="election-name"
              className="text-lg font-medium text-gray-900"
            >
              {nextElection.name}
            </p>
            <p data-testid="election-date" className="text-gray-600 mt-1">
              {formatDate(nextElection.date)}
              {nextElection.isPrimary && nextElection.primaryType && (
                <span className="ml-2 text-sm text-gray-500">
                  ({nextElection.primaryType} primary)
                </span>
              )}
            </p>
          </div>

          {/* Registration Deadlines */}
          <div
            data-testid="registration-status"
            className="mb-4 pb-4 border-b border-gray-100"
          >
            <h3 className="text-sm font-medium text-gray-500 uppercase tracking-wide mb-2">
              Registration Deadlines
            </h3>

            {allDeadlinesPassed && (
              <div
                className="mb-3 p-3 bg-amber-50 border border-amber-200 rounded-lg text-sm text-amber-800"
                role="alert"
              >
                Registration deadlines for this election have passed. Check{" "}
                <a
                  href={stateData.registration.registrationCheckUrl}
                  target="_blank"
                  rel="noopener noreferrer"
                  className="underline"
                >
                  here
                </a>{" "}
                to confirm your registration status.
              </div>
            )}

            {stateData.registration.online.available ? (
              <DeadlineStatus
                label="Online registration"
                deadline={stateData.registration.online.deadline}
                result={onlineStatus}
              />
            ) : (
              <div className="flex items-center justify-between gap-2 py-1">
                <span className="text-sm text-gray-700">
                  Online registration
                </span>
                <span className="text-xs text-gray-500 px-2 py-0.5 rounded-full bg-gray-100">
                  Not available
                </span>
              </div>
            )}

            <DeadlineStatus
              label={`Register by mail${stateData.registration.byMail.sincePostmarked ? " (postmark)" : ""}`}
              deadline={stateData.registration.byMail.deadline}
              result={byMailStatus}
            />

            <DeadlineStatus
              label="Register in person"
              deadline={stateData.registration.inPerson.deadline}
              result={inPersonStatus}
            />

            {stateData.registration.sameDayRegistration && (
              <p className="text-xs text-green-700 mt-1">
                Same-day registration available
              </p>
            )}
          </div>

          {/* Early Voting */}
          <div className="mb-4 pb-4 border-b border-gray-100">
            <h3 className="text-sm font-medium text-gray-500 uppercase tracking-wide mb-2">
              Early Voting
            </h3>
            {stateData.earlyVoting.available &&
            stateData.earlyVoting.startDate &&
            stateData.earlyVoting.endDate ? (
              <p className="text-sm text-gray-700">
                {formatDate(stateData.earlyVoting.startDate)} –{" "}
                {formatDate(stateData.earlyVoting.endDate)}
                {stateData.earlyVoting.notes && (
                  <span className="block text-xs text-gray-500 mt-1">
                    {stateData.earlyVoting.notes}
                  </span>
                )}
              </p>
            ) : (
              <p className="text-sm text-gray-700">
                {stateData.earlyVoting.notes ||
                  "Not available — absentee voting only"}
              </p>
            )}
          </div>

          {/* Voting Rules */}
          <div className="mb-4 pb-4 border-b border-gray-100">
            <h3 className="text-sm font-medium text-gray-500 uppercase tracking-wide mb-2">
              Voting Rules
            </h3>
            <div className="space-y-2 text-sm text-gray-700">
              <p>
                <span className="font-medium">Voter ID:</span>{" "}
                {stateData.votingRules.idRequired ? "Required" : "Not required"}
              </p>
              <p>
                <span className="font-medium">Phones at polls:</span>{" "}
                {stateData.votingRules.phonesAtPollsDetail}
              </p>
              {stateData.votingRules.additionalRules.map((rule, i) => (
                <p key={i}>{rule}</p>
              ))}
            </div>
          </div>

          {/* Resources */}
          <div>
            <h3 className="text-sm font-medium text-gray-500 uppercase tracking-wide mb-2">
              Official Resources
            </h3>
            <div className="space-y-1">
              <a
                href={stateData.resources.countyElectionLookup}
                target="_blank"
                rel="noopener noreferrer"
                className="block text-sm text-blue-600 underline hover:text-blue-800"
              >
                County election office
              </a>
              <a
                href={stateData.resources.sampleBallotLookup}
                target="_blank"
                rel="noopener noreferrer"
                className="block text-sm text-blue-600 underline hover:text-blue-800"
              >
                Sample ballot lookup
              </a>
              <a
                href={stateData.resources.stateElectionWebsite}
                target="_blank"
                rel="noopener noreferrer"
                className="block text-sm text-blue-600 underline hover:text-blue-800"
              >
                {stateData.stateName} election website
              </a>
            </div>
          </div>
        </>
      )}
    </div>
  );
}

"use client";

interface StateSelectorProps {
  stateCodes: string[];
  onSelect: (code: string) => void;
}

// Map of state codes to state names
const STATE_NAMES: Record<string, string> = {
  AZ: "Arizona",
  CA: "California",
  NM: "New Mexico",
  NH: "New Hampshire",
  TX: "Texas",
};

export function StateSelectorModal({
  stateCodes,
  onSelect,
}: StateSelectorProps) {
  return (
    <div
      data-testid="state-selector"
      className="bg-white border border-gray-200 rounded-xl p-6 shadow-sm"
      role="region"
      aria-label="State selector"
    >
      <h2 className="text-lg font-semibold text-gray-900 mb-2">
        This zip code spans multiple states
      </h2>
      <p className="text-sm text-gray-600 mb-4">
        Which state are you voting in?
      </p>
      <div className="flex flex-col gap-2">
        {stateCodes.map((code) => (
          <button
            key={code}
            onClick={() => onSelect(code)}
            className="w-full px-4 py-3 text-left border border-gray-300 rounded-lg hover:border-blue-500 hover:bg-blue-50 focus:outline-none focus:ring-2 focus:ring-blue-500 font-medium text-gray-900 min-h-[44px]"
            aria-label={`Select ${STATE_NAMES[code] ?? code}`}
          >
            {STATE_NAMES[code] ?? code} ({code})
          </button>
        ))}
      </div>
    </div>
  );
}

"use client";

import { useState } from "react";

interface ZipCodeFormProps {
  onSubmit: (zip: string) => void;
  isLoading?: boolean;
}

export function ZipCodeForm({ onSubmit, isLoading = false }: ZipCodeFormProps) {
  const [zipValue, setZipValue] = useState("");
  const [error, setError] = useState<string | null>(null);

  function validate(value: string): string | null {
    if (!value || value.trim() === "") {
      return "Please enter a zip code";
    }
    if (!/^\d{5}$/.test(value.trim())) {
      return "Please enter a valid 5-digit zip code";
    }
    return null;
  }

  function handleSubmit(e: React.FormEvent) {
    e.preventDefault();
    const err = validate(zipValue);
    if (err) {
      setError(err);
      return;
    }
    setError(null);
    onSubmit(zipValue.trim());
  }

  function handleChange(e: React.ChangeEvent<HTMLInputElement>) {
    setZipValue(e.target.value);
    if (error) {
      setError(null);
    }
  }

  return (
    <form onSubmit={handleSubmit} noValidate>
      <div className="flex flex-col gap-2">
        <label
          htmlFor="zip-input"
          className="text-sm font-medium text-gray-700"
        >
          Enter your 5-digit zip code
        </label>
        <div className="flex gap-2">
          <input
            id="zip-input"
            data-testid="zip-input"
            type="text"
            inputMode="numeric"
            pattern="[0-9]{5}"
            maxLength={5}
            value={zipValue}
            onChange={handleChange}
            placeholder="e.g. 73301"
            className="flex-1 min-w-0 px-4 py-3 text-base border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-blue-500 focus:border-transparent"
            aria-describedby={error ? "zip-error" : undefined}
            aria-invalid={error ? "true" : "false"}
            disabled={isLoading}
          />
          <button
            type="submit"
            data-testid="zip-submit"
            disabled={isLoading}
            className="px-6 py-3 bg-blue-600 text-white font-medium rounded-lg hover:bg-blue-700 focus:outline-none focus:ring-2 focus:ring-blue-500 focus:ring-offset-2 disabled:opacity-50 disabled:cursor-not-allowed min-w-[120px] min-h-[44px]"
          >
            {isLoading ? "Loading..." : "Look Up"}
          </button>
        </div>
        {error && (
          <p
            id="zip-error"
            data-testid="zip-error"
            role="alert"
            className="text-sm text-red-600 mt-1"
          >
            {error}
          </p>
        )}
      </div>
    </form>
  );
}

import { describe, it, expect } from "vitest";
import {
  getDeadlineStatus,
  formatDate,
  findNextElection,
} from "../deadlineStatus";
import type { Election } from "../types";

const TODAY = new Date(2026, 4, 11); // May 11, 2026

describe("getDeadlineStatus", () => {
  it("returns passed for a deadline in the past", () => {
    const result = getDeadlineStatus("2026-02-01", TODAY);
    expect(result.status).toBe("passed");
    expect(result.label).toBe("Passed");
  });

  it("returns urgent for a deadline 1 day away", () => {
    const result = getDeadlineStatus("2026-05-12", TODAY);
    expect(result.status).toBe("urgent");
    expect(result.daysRemaining).toBe(1);
  });

  it("returns urgent for a deadline 3 days away", () => {
    const result = getDeadlineStatus("2026-05-14", TODAY);
    expect(result.status).toBe("urgent");
    expect(result.daysRemaining).toBe(3);
  });

